module MijDerivs
using StaticArrays

δ(x::Int, y::Int)::Int = x == y ? 1 : 0

Mij2(i::Int64, j::Int64, x::MVector{3, Float64}, dx::MVector{3, Float64}, d2x::MVector{3, Float64}, d3x::MVector{3, Float64}, d4x::MVector{3, Float64}, d5x::MVector{3, Float64}, d6x::MVector{3, Float64}, d7x::MVector{3, Float64}, d8x::MVector{3, Float64}, d9x::MVector{3, Float64}, m::Float64, ν::Float64)::Float64 = 2 * dx[i] * dx[j] + (δ(i, j) * (((((-2 * dx[1] ^ 2 - 2 * dx[2] ^ 2) - 2 * dx[3] ^ 2) - 2 * x[1] * d2x[1]) - 2 * x[2] * d2x[2]) - 2 * x[3] * d2x[3])) / 3.0 + x[j] * d2x[i] + x[i] * d2x[j]

Mij5(i::Int64, j::Int64, x::MVector{3, Float64}, dx::MVector{3, Float64}, d2x::MVector{3, Float64}, d3x::MVector{3, Float64}, d4x::MVector{3, Float64}, d5x::MVector{3, Float64}, d6x::MVector{3, Float64}, d7x::MVector{3, Float64}, d8x::MVector{3, Float64}, d9x::MVector{3, Float64}, m::Float64, ν::Float64)::Float64 = 10 * d2x[j] * d3x[i] + 10 * d2x[i] * d3x[j] + 5 * dx[j] * d4x[i] + 5 * dx[i] * d4x[j] + (δ(i, j) * ((((((((-20 * d2x[1] * d3x[1] - 20 * d2x[2] * d3x[2]) - 20 * d2x[3] * d3x[3]) - 10 * dx[1] * d4x[1]) - 10 * dx[2] * d4x[2]) - 10 * dx[3] * d4x[3]) - 2 * x[1] * d5x[1]) - 2 * x[2] * d5x[2]) - 2 * x[3] * d5x[3])) / 3.0 + x[j] * d5x[i] + x[i] * d5x[j]

Mij6(i::Int64, j::Int64, x::MVector{3, Float64}, dx::MVector{3, Float64}, d2x::MVector{3, Float64}, d3x::MVector{3, Float64}, d4x::MVector{3, Float64}, d5x::MVector{3, Float64}, d6x::MVector{3, Float64}, d7x::MVector{3, Float64}, d8x::MVector{3, Float64}, d9x::MVector{3, Float64}, m::Float64, ν::Float64)::Float64 = 20 * d3x[i] * d3x[j] + 15 * d2x[j] * d4x[i] + 15 * d2x[i] * d4x[j] + 6 * dx[j] * d5x[i] + 6 * dx[i] * d5x[j] + (δ(i, j) * (((((((((((-20 * d3x[1] ^ 2 - 20 * d3x[2] ^ 2) - 20 * d3x[3] ^ 2) - 30 * d2x[1] * d4x[1]) - 30 * d2x[2] * d4x[2]) - 30 * d2x[3] * d4x[3]) - 12 * dx[1] * d5x[1]) - 12 * dx[2] * d5x[2]) - 12 * dx[3] * d5x[3]) - 2 * x[1] * d6x[1]) - 2 * x[2] * d6x[2]) - 2 * x[3] * d6x[3])) / 3.0 + x[j] * d6x[i] + x[i] * d6x[j]

Mij7(i::Int64, j::Int64, x::MVector{3, Float64}, dx::MVector{3, Float64}, d2x::MVector{3, Float64}, d3x::MVector{3, Float64}, d4x::MVector{3, Float64}, d5x::MVector{3, Float64}, d6x::MVector{3, Float64}, d7x::MVector{3, Float64}, d8x::MVector{3, Float64}, d9x::MVector{3, Float64}, m::Float64, ν::Float64)::Float64 = 35 * d3x[j] * d4x[i] + 35 * d3x[i] * d4x[j] + 21 * d2x[j] * d5x[i] + 21 * d2x[i] * d5x[j] + 7 * dx[j] * d6x[i] + 7 * dx[i] * d6x[j] + (δ(i, j) * (((((((((((-70 * d3x[1] * d4x[1] - 70 * d3x[2] * d4x[2]) - 70 * d3x[3] * d4x[3]) - 42 * d2x[1] * d5x[1]) - 42 * d2x[2] * d5x[2]) - 42 * d2x[3] * d5x[3]) - 14 * dx[1] * d6x[1]) - 14 * dx[2] * d6x[2]) - 14 * dx[3] * d6x[3]) - 2 * x[1] * d7x[1]) - 2 * x[2] * d7x[2]) - 2 * x[3] * d7x[3])) / 3.0 + x[j] * d7x[i] + x[i] * d7x[j]

Mij8(i::Int64, j::Int64, x::MVector{3, Float64}, dx::MVector{3, Float64}, d2x::MVector{3, Float64}, d3x::MVector{3, Float64}, d4x::MVector{3, Float64}, d5x::MVector{3, Float64}, d6x::MVector{3, Float64}, d7x::MVector{3, Float64}, d8x::MVector{3, Float64}, d9x::MVector{3, Float64}, m::Float64, ν::Float64)::Float64 = 70 * d4x[i] * d4x[j] + 56 * d3x[j] * d5x[i] + 56 * d3x[i] * d5x[j] + 28 * d2x[j] * d6x[i] + 28 * d2x[i] * d6x[j] + 8 * dx[j] * d7x[i] + 8 * dx[i] * d7x[j] + (δ(i, j) * ((((((((((((((-70 * d4x[1] ^ 2 - 70 * d4x[2] ^ 2) - 70 * d4x[3] ^ 2) - 112 * d3x[1] * d5x[1]) - 112 * d3x[2] * d5x[2]) - 112 * d3x[3] * d5x[3]) - 56 * d2x[1] * d6x[1]) - 56 * d2x[2] * d6x[2]) - 56 * d2x[3] * d6x[3]) - 16 * dx[1] * d7x[1]) - 16 * dx[2] * d7x[2]) - 16 * dx[3] * d7x[3]) - 2 * x[1] * d8x[1]) - 2 * x[2] * d8x[2]) - 2 * x[3] * d8x[3])) / 3.0 + x[j] * d8x[i] + x[i] * d8x[j]

end